INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'He is _____ honest man and everyone trusts him.', '["A. a", "B. an", "C. the", "D. /"]', '["B"]', 'honest以元音音素开头，用an表示泛指。', 'easy', (SELECT id FROM knowledge_point WHERE name='语法' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='语法' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'Not until he left his home _____ how important the family was for him.', '["A. did he realize", "B. he realized", "C. had he realized", "D. he had realized"]', '["A"]', 'Not until置于句首时主句需部分倒装。left为过去式，用did he realize保持一致。', 'medium', (SELECT id FROM knowledge_point WHERE name='语法' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='语法' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', 'It is no use _____ (cry) over spilt milk. (用所给词的正确形式填空)', '[]', '["crying"]', 'It is no use doing sth. 为固定句型，表示做某事没有用。', 'medium', (SELECT id FROM knowledge_point WHERE name='语法' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='语法' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', 'The factory _____ (build) at present will be the largest one in the city. (用所给词的正确形式填空)', '[]', '["being built"]', 'at present表示正在进行的动作，factory与build是被动关系，用现在分词的被动式being built作后置定语。', 'hard', (SELECT id FROM knowledge_point WHERE name='语法' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='语法' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '请辨析三个短语的用法区别：used to do, be used to doing, be used to do。各举一例。', '[]', '["used to do表示过去常常做某事(现已不做)，如I used to swim every day. be used to doing表示习惯于做某事，如I am used to getting up early. be used to do表示被用来做某事，如This knife is used to cut bread."]', '三个短语形似但意义完全不同。used to do中to是不定式符号；be used to doing中to是介词后接动名词；be used to do是use的被动语态。', 'hard', (SELECT id FROM knowledge_point WHERE name='语法' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='语法' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'She was so _____ in her book that she didn''t hear me come in.', '["A. absorbed", "B. attracted", "C. drawn", "D. concentrated"]', '["A"]', 'be absorbed in为固定搭配，表示全神贯注于。concentrate需搭配on。', 'medium', (SELECT id FROM knowledge_point WHERE name='完形' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='完形' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'The little boy _____ the toy car, but it didn''t work.', '["A. tried to fix", "B. tried fixing", "C. managed to fix", "D. succeeded in fixing"]', '["B"]', 'try doing表示试着做(尝试)，try to do表示努力做。根据句意试着修但没修好，用tried fixing。', 'medium', (SELECT id FROM knowledge_point WHERE name='完形' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='完形' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', 'The teacher, as well as her students, _____ (be) going to the museum. (用所给词的适当形式填空)', '[]', '["is"]', 'as well as连接主语时，谓语动词与前面的主语保持一致(就远原则)。the teacher是单数，用is。', 'medium', (SELECT id FROM knowledge_point WHERE name='完形' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='完形' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'What is the author''s attitude towards the rapid development of AI?
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', 'Reading: The passage claims that AI will completely replace human teachers within 10 years as a confirmed fact. (T/F)', '[]', '"F"', '极端绝对说法通常不是文章陈述的事实，更可能是某个观点或未在文中讨论。', 'easy', (SELECT id FROM knowledge_point WHERE name='阅读' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='阅读' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', 'The author''s tone in discussing environmental policies suggests cautious optimism about future progress. (T/F)', '[]', '"T"', '通过作者使用progress和challenges remain并存的行文方式，可推断其谨慎乐观态度。', 'medium', (SELECT id FROM knowledge_point WHERE name='阅读' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='阅读' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', 'What is the main purpose of a persuasive essay? List at least 3 rhetorical devices used to achieve this purpose.', '[]', '["Purpose: to convince the reader to accept a viewpoint. Devices: 1. Rhetorical questions 2. Statistics and evidence 3. Appeal to emotion (pathos) 4. Appeal to credibility (ethos) 5. Logical reasoning (logos)."]', '说服性文章三大核心手法为ethos(信誉建立)、pathos(情感共鸣)和logos(逻辑论证)。', 'hard', (SELECT id FROM knowledge_point WHERE name='阅读' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='阅读' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'When preparing for an exam, it is important to have a study plan. _____. Without a plan, you may find yourself cramming at the last minute.', '["A. A good plan helps you manage your time effectively", "B. Exams are always stressful for students", "C. Many students don''t like studying for exams", "D. You should study every subject equally"]', '["A"]', 'A选项承上启下，解释学习计划的作用——有效管理时间。其他选项与上下文逻辑不连贯。', 'medium', (SELECT id FROM knowledge_point WHERE name='七选五' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='七选五' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', 'Which of the following are effective reading strategies? (Choose all that apply)', '["A. Previewing the text before reading", "B. Skipping all unfamiliar words", "C. Making predictions while reading", "D. Summarizing after each paragraph"]', '["[\"A\", \"C\", \"D\"]"]', 'Previewing、making predictions、summarizing都是有效阅读策略。跳过所有生词不利于理解，应通过上下文推测词义。', 'medium', (SELECT id FROM knowledge_point WHERE name='七选五' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='七选五' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', '在七选五阅读题型中，成功解题需要哪三项核心技能？请简要说明。', '[]', '["1. 语篇连贯性识别——理解句子间如何衔接；2. 逻辑关系推理——识别因果、对比、递进等逻辑关系；3. 衔接词把握——识别过渡词和篇章标记语。"]', '七选五考查核心为：语篇连贯理解、逻辑关系判断和衔接手段识别。', 'hard', (SELECT id FROM knowledge_point WHERE name='七选五' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='七选五' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '短文改错: She go to school by bus every day. 请选择正确的修改方式:', '["A. go→goes", "B. go→went", "C. go→going", "D. bus→the bus"]', '["A"]', '主语She是第三人称单数，一般现在时需用goes。by bus为固定搭配，无需加冠词。', 'easy', (SELECT id FROM knowledge_point WHERE name='改错' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='改错' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', 'Error correction: ''If I was you, I would accept the offer.'' This sentence is grammatically correct. (T/F)', '[]', '"F"', '虚拟语气中与现在事实相反应用If I were you，be动词用were而非was。', 'easy', (SELECT id FROM knowledge_point WHERE name='改错' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='改错' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '改错题: There are many student in the classroom. (写出正确的句子)', '[]', '["There are many students in the classroom."]', 'many后接可数名词复数形式，student需加s。', 'medium', (SELECT id FROM knowledge_point WHERE name='改错' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='改错' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '以下哪个句子最适合作为建议信的英文开头?', '["A. I''m writing to express my sincere gratitude.", "B. I''m writing to offer some suggestions regarding...", "C. I''m terribly sorry for the inconvenience.", "D. I would like to apply for the position of..."]', '["B"]', '建议信开头应明确写作目的——提出建议。A为感谢信，C为道歉信，D为申请信。', 'medium', (SELECT id FROM knowledge_point WHERE name='写作' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='写作' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '以下哪个过渡词最适合表示对比关系?', '["A. Furthermore", "B. However", "C. Therefore", "D. For example"]', '["B"]', 'However表示转折/对比。Furthermore表示递进，Therefore表示因果，For example表示举例。', 'easy', (SELECT id FROM knowledge_point WHERE name='写作' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='写作' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', 'Write an outline for a 100-word English essay on the topic: The Impact of Social Media on Teenagers. Include introduction, body (2 points), and conclusion.', '[]', '["Introduction: Social media is a double-edged sword for teenagers. Body: (1) Positive impacts - easy communication, educational resources. (2) Negative impacts - addiction, mental health issues, cyberbullying. Conclusion: Balanced use is essential; parents and schools should guide teenagers."]', '议论文应结构清晰：引言提出主题论点，正文分正反两面论述，结论总结并给出建议。', 'hard', (SELECT id FROM knowledge_point WHERE name='写作' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='写作' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'The word extraordinary is closest in meaning to:', '["A. ordinary", "B. remarkable", "C. additional", "D. basic"]', '["B"]', 'extraordinary意为非凡的、卓越的，与remarkable同义。ordinary是其反义词。', 'easy', (SELECT id FROM knowledge_point WHERE name='词汇' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='词汇' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'We should _____ every opportunity to practice speaking English.', '["A. take advantage of", "B. take care of", "C. take charge of", "D. take notice of"]', '["A"]', 'take advantage of意为利用(机会)。take care of照顾，take charge of负责，take notice of注意。', 'medium', (SELECT id FROM knowledge_point WHERE name='词汇' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='词汇' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', 'Which of the following phrases express cause and effect? (Choose all that apply)', '["A. lead to", "B. result in", "C. contribute to", "D. consist of"]', '["[\"A\", \"B\", \"C\"]"]', 'lead to、result in、contribute to都可表示导致、引起。consist of表示由...组成。', 'medium', (SELECT id FROM knowledge_point WHERE name='词汇' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='词汇' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', 'He has a good _____ (command) of English. (用所给词的适当形式填空)', '[]', '["command"]', 'have a good command of为固定短语，意为精通掌握。command在此为名词。', 'medium', (SELECT id FROM knowledge_point WHERE name='词汇' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='词汇' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', 'The phrasal verb break down can mean both stop functioning and lose control of emotions. (T/F)', '[]', '"T"', 'break down确实有机器出故障和情绪崩溃两种含义。', 'easy', (SELECT id FROM knowledge_point WHERE name='词汇' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='词汇' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'By the time he arrives, we _____ for three hours.', '["A. will have been waiting", "B. will wait", "C. have waited", "D. are waiting"]', '["A"]', 'by the time+现在时，主句用将来完成时。for three hours表持续，用将来完成进行时。', 'easy', (SELECT id FROM knowledge_point WHERE name='时态语态' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='时态语态' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'The new bridge _____ by the end of next year.', '["A. will complete", "B. will be completed", "C. will have been completed", "D. has been completed"]', '["C"]', 'by+将来时间+被动语态=将来完成时被动式will have been completed。', 'medium', (SELECT id FROM knowledge_point WHERE name='时态语态' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='时态语态' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', 'This is the first time that I _____ (visit) the Great Wall. (用所给词的适当形式填空)', '[]', '["have visited"]', 'This/It is the first time that...句式中，that从句用现在完成时。', 'medium', (SELECT id FROM knowledge_point WHERE name='时态语态' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='时态语态' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', 'The sentence ''The book sells well'' is grammatically incorrect because sell should be in the passive voice. (T/F)', '[]', '"F"', 'The book sells well是正确的主动形式表被动意义，描述事物内在属性。类似用法有The cloth washes well。', 'easy', (SELECT id FROM knowledge_point WHERE name='时态语态' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='时态语态' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', 'Which of the following sentences use the correct tense? (Choose all that apply)', '["A. I have known him since 2018.", "B. She has gone to Beijing and will be back next week.", "C. They had finished the work before the boss arrived.", "D. By next month we will have been living here for ten years."]', '["[\"A\", \"B\", \"C\", \"D\"]"]', 'since+过去时间用现在完成时；has gone to表已去某地未归；before从句过去时主句过去完成时；by next month表将来时间用将来完成进行时。全部正确。', 'medium', (SELECT id FROM knowledge_point WHERE name='时态语态' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='时态语态' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'This is the village _____ I was born and grew up.', '["A. which", "B. that", "C. where", "D. when"]', '["C"]', '定语从句缺少地点状语，用where=in which。', 'easy', (SELECT id FROM knowledge_point WHERE name='从句' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='从句' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '_____ is known to all, China has made great achievements in space exploration.', '["A. As", "B. Which", "C. That", "D. What"]', '["A"]', 'as引导非限制性定语从句指代整个主句内容，可置于句首。which也可引导但不能放在句首。', 'medium', (SELECT id FROM knowledge_point WHERE name='从句' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='从句' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', 'Which of the following contain noun clauses? (Choose all that apply)', '["A. What he said surprised everyone.", "B. The fact that he passed the exam is true.", "C. I don''t know where he lives.", "D. The man who is standing there is my uncle."]', '["[\"A\", \"B\", \"C\"]"]', 'A是主语从句，B是同位语从句，C是宾语从句。D是定语从句(形容词性从句)，不属于名词性从句。', 'hard', (SELECT id FROM knowledge_point WHERE name='从句' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='从句' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', 'The reason _____ he was late was that his car broke down on the way.', '[]', '["why"]', 'the reason后接定语从句用why引导(也可用that或省略)。', 'medium', (SELECT id FROM knowledge_point WHERE name='从句' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='从句' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'short_answer', 'Distinguish restrictive and non-restrictive relative clauses. Give one example of each.', '[]', '["Restrictive clause: essential to identify the antecedent, no commas. e.g. The book that I bought yesterday is interesting. Non-restrictive clause: provides extra information, set off by commas. e.g. My father, who is a doctor, works long hours."]', '限制性定语从句是确定先行词的必要信息，不用逗号，可用that；非限制性提供附加信息，用逗号隔开，不用that引导。', 'hard', (SELECT id FROM knowledge_point WHERE name='从句' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='从句' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', '_____ from the top of the mountain, the city looks beautiful.', '["A. Seeing", "B. Seen", "C. To see", "D. Having seen"]', '["B"]', 'the city与see是被动关系(城市被看)，用过去分词Seen作状语。', 'easy', (SELECT id FROM knowledge_point WHERE name='非谓语' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='非谓语' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'single_choice', 'He is said _____ abroad, but I don''t know which country he studied in.', '["A. to study", "B. to be studying", "C. to have studied", "D. studying"]', '["C"]', 'be said to have done为固定句型，study发生在is said之前，用不定式完成式。', 'medium', (SELECT id FROM knowledge_point WHERE name='非谓语' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='非谓语' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'fill_blank', '_____ (finish) his homework, Tom went out to play basketball. (用所给词的正确形式填空)', '[]', '["Having finished"]', 'finish发生在went out之前，且与主语Tom是主动关系，用现在分词完成式Having finished作状语。', 'medium', (SELECT id FROM knowledge_point WHERE name='非谓语' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='非谓语' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'multi_choice', 'Which sentences correctly use non-finite verbs? (Choose all that apply)', '["A. The problem to be discussed tomorrow is important.", "B. I remember locking the door before I left.", "C. Being ill, she stayed at home.", "D. The boy stood there, with his eyes fixed on the screen."]', '["[\"A\", \"B\", \"C\", \"D\"]"]', 'A不定式被动做定语表将来；B动名词做remember宾语表已做；C现在分词作原因状语；D with复合结构中过去分词表被动状态。全部正确。', 'hard', (SELECT id FROM knowledge_point WHERE name='非谓语' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='非谓语' AND subject='english');
INSERT INTO question_bank (type, title, options, answer, explanation, difficulty, knowledge_point_id, created_at) SELECT 'true_false', 'The sentence ''I''m looking forward to hear from you'' is grammatically correct. (T/F)', '[]', '"F"', 'look forward to中to是介词后接名词或动名词，应为looking forward to hearing from you。', 'medium', (SELECT id FROM knowledge_point WHERE name='非谓语' AND subject='english' LIMIT 1), NOW() WHERE EXISTS (SELECT 1 FROM knowledge_point WHERE name='非谓语' AND subject='english');
